## Objective

Implement the attribute parsing and handling for `#[init]`, `#[update]`, and `#[view]` attributes that mark methods on Model structs. These attributes identify which methods implement the Model trait's required functionality.

## Detailed Requirements

### 1. Darling Attribute Definitions

```rust
// crates/bubbletea-macros/src/attributes.rs
use darling::{FromDeriveInput, FromField, FromMeta};
use syn::{Ident, Type, Visibility};

/// Configuration for the #[derive(Model)] macro
#[derive(Debug, FromDeriveInput)]
#[darling(attributes(model), supports(struct_named))]
pub struct ModelArgs {
    pub ident: Ident,
    pub vis: Visibility,
    pub data: darling::ast::Data<(), FieldArgs>,

    /// Optional custom message type (defaults to `Msg`)
    #[darling(default)]
    pub message: Option<Type>,
}

/// Configuration for struct fields
#[derive(Debug, FromField)]
#[darling(attributes(state))]
pub struct FieldArgs {
    pub ident: Option<Ident>,
    pub ty: Type,
    pub vis: Visibility,

    /// Mark field as state that triggers re-render
    #[darling(default)]
    pub state: bool,
}

/// Configuration for #[init] attribute
#[derive(Debug, Default, FromMeta)]
pub struct InitArgs {
    /// Custom command to return (defaults to Command::none())
    #[darling(default)]
    pub command: Option<syn::Path>,
}

/// Configuration for #[update] attribute  
#[derive(Debug, Default, FromMeta)]
pub struct UpdateArgs {
    /// Message variant patterns to handle
    #[darling(default)]
    pub handles: Option<Vec<syn::Pat>>,
}

/// Configuration for #[view] attribute
#[derive(Debug, Default, FromMeta)]
pub struct ViewArgs {
    /// Optional viewport dimensions
    #[darling(default)]
    pub width: Option<usize>,
    #[darling(default)]
    pub height: Option<usize>,
