```

### 2. Attribute Detection and Extraction

```rust
// crates/bubbletea-macros/src/attributes.rs

use syn::{ImplItem, ImplItemFn, ItemImpl};
use proc_macro_error::abort;

/// Parsed method information from impl block
pub struct ParsedMethods {
    pub init: Option<ImplItemFn>,
    pub update: Option<ImplItemFn>,
    pub view: Option<ImplItemFn>,
}

impl ParsedMethods {
    /// Extract attributed methods from an impl block
    pub fn from_impl(impl_block: &ItemImpl) -> Self {
        let mut init = None;
        let mut update = None;
        let mut view = None;

        for item in &impl_block.items {
            if let ImplItem::Fn(method) = item {
                for attr in &method.attrs {
                    if attr.path().is_ident("init") {
                        if init.is_some() {
                            abort!(method.sig.ident.span(), 
                                "Multiple #[init] methods found; only one is allowed");
                        }
                        init = Some(method.clone());
                    } else if attr.path().is_ident("update") {
                        if update.is_some() {
                            abort!(method.sig.ident.span(),
                                "Multiple #[update] methods found; only one is allowed");
                        }
                        update = Some(method.clone());
                    } else if attr.path().is_ident("view") {
                        if view.is_some() {
                            abort!(method.sig.ident.span(),
                                "Multiple #[view] methods found; only one is allowed");
                        }
                        view = Some(method.clone());
                    }
                }
            }
        }

        ParsedMethods { init, update, view }
    }
}
```

### 3. Method Signature Validation

```rust
// crates/bubbletea-macros/src/attributes.rs

use syn::{FnArg, ReturnType, Signature};

pub fn validate_init_signature(sig: &Signature, struct_name: &Ident) -> Result<(), syn::Error> {
    // Must be fn init() -> (Self, Command<Msg>)
    if !sig.inputs.is_empty() {
        return Err(syn::Error::new_spanned(
            &sig.inputs,
            "#[init] method must take no arguments"
        ));
    }

    // Return type validation
    match &sig.output {
        ReturnType::Default => {
            return Err(syn::Error::new_spanned(
                sig,
                format!("#[init] must return (Self, Command<Msg>) or ({}, Command<Msg>)", struct_name)
            ));
        }
        ReturnType::Type(_, ty) => {
            // Validate it's a tuple with (Self/StructName, Command<_>)
            validate_init_return_type(ty, struct_name)?;
        }
    }
    Ok(())
}

pub fn validate_update_signature(sig: &Signature) -> Result<(), syn::Error> {
    // Must be fn update(&mut self, msg: Msg) -> Command<Msg>
    let mut has_self_mut = false;
    let mut has_msg = false;

    for input in &sig.inputs {
        match input {
            FnArg::Receiver(recv) => {
                if recv.mutability.is_none() {
                    return Err(syn::Error::new_spanned(
                        recv,
                        "#[update] method must take &mut self"
                    ));
                }
                has_self_mut = true;
            }
            FnArg::Typed(_) => {
                has_msg = true;
            }
        }
    }

    if !has_self_mut {
        return Err(syn::Error::new_spanned(
            sig,
            "#[update] method must take &mut self as first argument"
        ));
    }

    if !has_msg {
        return Err(syn::Error::new_spanned(
            sig,
            "#[update] method must take a message argument"
        ));
    }

    Ok(())
}

pub fn validate_view_signature(sig: &Signature) -> Result<(), syn::Error> {
    // Must be fn view(&self) -> String
    for input in &sig.inputs {
        if let FnArg::Receiver(recv) = input {
            if recv.mutability.is_some() {
                return Err(syn::Error::new_spanned(
                    recv,
                    "#[view] method should take &self, not &mut self"
                ));
            }
        }
    }

    // Validate returns String
    if let ReturnType::Type(_, ty) = &sig.output {
        // Could be String, &str, impl Display, etc.
        // For now, just ensure it has a return type
    } else {
        return Err(syn::Error::new_spanned(
            sig,
            "#[view] method must return a String"
        ));
    }

    Ok(())
}
```

### 4. Code Generation for Trait Implementation

```rust
// crates/bubbletea-macros/src/model.rs
use quote::quote;
use proc_macro2::TokenStream;

pub fn generate_model_impl(
    struct_name: &Ident,
    methods: &ParsedMethods,
    msg_type: &Type,
) -> TokenStream {
    let init_body = methods.init.as_ref().map(|m| &m.block);
    let update_body = methods.update.as_ref().map(|m| &m.block);
    let view_body = methods.view.as_ref().map(|m| &m.block);

    quote! {
        impl bubbletea::Model for #struct_name {
            type Message = #msg_type;

            fn init() -> (Self, bubbletea::Command<Self::Message>) {
                #init_body
            }

            fn update(&mut self, msg: Self::Message) -> bubbletea::Command<Self::Message> {
                #update_body
            }

            fn view(&self) -> String {
                #view_body
            }
        }
    }
}
```

