## Objective
Implement a middleware system that allows pre/post processing of SSH connections, authentication, and requests.

## Implementation Details

### Middleware Trait
```rust
use async_trait::async_trait;

#[async_trait]
pub trait Middleware: Send + Sync {
    /// Called when a new connection is established
    async fn on_connect(&self, ctx: &mut ConnectionContext) -> MiddlewareResult {
        MiddlewareResult::Continue
    }

    /// Called after successful authentication
    async fn on_auth(&self, ctx: &mut AuthContext) -> MiddlewareResult {
        MiddlewareResult::Continue
    }

    /// Called when a session/channel is opened
    async fn on_session_start(&self, ctx: &mut SessionContext) -> MiddlewareResult {
        MiddlewareResult::Continue
    }

    /// Called when a session ends
    async fn on_session_end(&self, ctx: &mut SessionContext) {
        // Default: no-op
    }

    /// Called on disconnect (clean or unclean)
    async fn on_disconnect(&self, ctx: &mut ConnectionContext) {
        // Default: no-op
    }

    /// Middleware name for logging
    fn name(&self) -> &'static str;
}

pub enum MiddlewareResult {
    Continue,
    Reject { reason: String },
}
```

### Middleware Chain
```rust
pub struct MiddlewareChain {
    middlewares: Vec<Arc<dyn Middleware>>,
}

impl MiddlewareChain {
    pub fn new() -> Self {
        Self { middlewares: Vec::new() }
    }

    pub fn add<M: Middleware + 'static>(&mut self, middleware: M) -> &mut Self {
        log::debug!("Adding middleware: {}", middleware.name());
        self.middlewares.push(Arc::new(middleware));
        self
    }

    pub async fn run_on_connect(&self, ctx: &mut ConnectionContext) -> MiddlewareResult {
        for mw in &self.middlewares {
            log::debug!("Running on_connect for middleware: {}", mw.name());
            match mw.on_connect(ctx).await {
                MiddlewareResult::Continue => continue,
                result @ MiddlewareResult::Reject { .. } => {
                    log::info!("Middleware {} rejected connection", mw.name());
                    return result;
                }
            }
        }
        MiddlewareResult::Continue
    }

    // Similar methods for on_auth, on_session_start, etc.
}
```

