#### Rate Limiting Middleware
```rust
use governor::{Quota, RateLimiter};

pub struct RateLimitMiddleware {
    limiter: RateLimiter<String, _, _>,
    max_connections_per_ip: u32,
}

#[async_trait]
impl Middleware for RateLimitMiddleware {
    async fn on_connect(&self, ctx: &mut ConnectionContext) -> MiddlewareResult {
        let key = ctx.peer_addr.ip().to_string();

        match self.limiter.check_key(&key) {
            Ok(_) => {
                log::debug!("Rate limit check passed for {}", key);
                MiddlewareResult::Continue
            }
            Err(_) => {
                log::warn!("Rate limit exceeded for {}", key);
                MiddlewareResult::Reject {
                    reason: "Rate limit exceeded".to_string(),
                }
            }
        }
    }

    fn name(&self) -> &'static str {
        "rate_limit"
    }
}
```

#### Ban List Middleware
```rust
pub struct BanListMiddleware {
    banned_ips: Arc<RwLock<HashSet<IpAddr>>>,
    banned_users: Arc<RwLock<HashSet<String>>>,
}

#[async_trait]
impl Middleware for BanListMiddleware {
    async fn on_connect(&self, ctx: &mut ConnectionContext) -> MiddlewareResult {
        let banned = self.banned_ips.read().await;
        if banned.contains(&ctx.peer_addr.ip()) {
            log::info!("Rejected banned IP: {}", ctx.peer_addr.ip());
            return MiddlewareResult::Reject {
                reason: "IP banned".to_string(),
            };
        }
        MiddlewareResult::Continue
    }

    async fn on_auth(&self, ctx: &mut AuthContext) -> MiddlewareResult {
        let banned = self.banned_users.read().await;
        if banned.contains(&ctx.username) {
            log::info!("Rejected banned user: {}", ctx.username);
            return MiddlewareResult::Reject {
                reason: "User banned".to_string(),
            };
        }
        MiddlewareResult::Continue
    }

    fn name(&self) -> &'static str {
        "ban_list"
    }
}
```

