## Objective
Create comprehensive e2e tests that simulate actual user interaction with examples, verifying complete user flows work correctly including terminal rendering and input handling.

## Detailed Requirements

### 1. Terminal Simulation Framework
Create `examples/e2e-tests/src/lib.rs`:
```rust
use std::time::Duration;
use std::io::{Read, Write};
use std::process::{Command, Stdio, Child};

/// Simulated terminal for e2e testing
pub struct TestTerminal {
    child: Child,
    stdin: std::process::ChildStdin,
    stdout: std::process::ChildStdout,
    buffer: String,
}

impl TestTerminal {
    /// Start an example in a pseudo-terminal
    pub fn spawn(example_name: &str) -> anyhow::Result<Self> {
        let mut child = Command::new("cargo")
            .args(["run", "-p", &format!("example-{}", example_name)])
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()?;

        let stdin = child.stdin.take().unwrap();
        let stdout = child.stdout.take().unwrap();

        Ok(Self {
            child,
            stdin,
            stdout,
            buffer: String::new(),
        })
    }

    /// Send a key press
    pub fn press_key(&mut self, key: &str) -> anyhow::Result<()> {
        let bytes = match key {
            "up" => "\x1b[A",
            "down" => "\x1b[B",
            "enter" => "\r",
            "escape" => "\x1b",
            "ctrl+c" => "\x03",
            "q" => "q",
            _ => key,
        };
        self.stdin.write_all(bytes.as_bytes())?;
        self.stdin.flush()?;
        Ok(())
    }

    /// Wait for output containing expected string
    pub fn wait_for(&mut self, expected: &str, timeout: Duration) -> anyhow::Result<()> {
        let start = std::time::Instant::now();
        let mut buf = [0u8; 1024];

        while start.elapsed() < timeout {
            if let Ok(n) = self.stdout.read(&mut buf) {
                self.buffer.push_str(&String::from_utf8_lossy(&buf[..n]));
                if self.buffer.contains(expected) {
                    return Ok(());
                }
            }
        }

        anyhow::bail!(
            "Timeout waiting for '{}'. Got:\n{}",
            expected,
            self.buffer
        )
    }

    /// Assert current screen contains text
    pub fn assert_screen_contains(&self, expected: &str) -> anyhow::Result<()> {
        if !self.buffer.contains(expected) {
            anyhow::bail!(
                "Screen should contain '{}'. Got:\n{}",
                expected,
                self.buffer
            );
        }
        Ok(())
    }

    /// Gracefully exit and wait for process
    pub fn exit(mut self) -> anyhow::Result<std::process::ExitStatus> {
        self.press_key("q")?;
