```rust
// crates/bubbletea-macros/src/lib.rs

//! # bubbletea-macros
//!
//! Procedural macros for the bubbletea TUI framework.
//!
//! This crate provides the `#[derive(Model)]` macro which reduces boilerplate
//! when implementing the `Model` trait for your TUI applications.
//!
//! ## Quick Start
//!
//! ```rust
//! use bubbletea::{Command, Model};
//! use bubbletea_macros::Model;
//!
//! // Define your message type
//! enum Msg {
//!     Increment,
//!     Decrement,
//!     Quit,
//! }
//!
//! // Derive Model automatically implements the trait
//! #[derive(Model)]
//! struct Counter {
//!     #[state]  // Marks fields that trigger re-renders
//!     count: i32,
//! }
//!
//! impl Counter {
//!     #[init]
//!     fn init() -> (Self, Command<Msg>) {
//!         (Counter { count: 0 }, Command::none())
//!     }
//!
//!     #[update]
//!     fn update(&mut self, msg: Msg) -> Command<Msg> {
//!         match msg {
//!             Msg::Increment => self.count += 1,
//!             Msg::Decrement => self.count -= 1,
//!             Msg::Quit => return Command::quit(),
//!         }
//!         Command::none()
//!     }
//!
//!     #[view]
//!     fn view(&self) -> String {
//!         format!("Count: {}\n\nPress +/- to change, q to quit", self.count)
//!     }
//! }
//! ```
//!
//! ## Attributes
//!
//! ### `#[derive(Model)]`
//!
//! Applied to a struct to derive the `Model` trait implementation.
//!
//! **Options:**
//! - `#[model(message = MyMsg)]` - Specify custom message type (defaults to `Msg`)
//!
//! ### `#[init]`
//!
//! Marks the initialization method. Must return `(Self, Command<Msg>)`.
//!
//! ```rust
//! #[init]
//! fn init() -> (Self, Command<Msg>) {
//!     (Self::default(), Command::none())
//! }
//!
//! // With startup command
//! #[init]
//! fn init() -> (Self, Command<Msg>) {
//!     (Self::default(), Command::perform(load_data(), Msg::DataLoaded))
//! }
//! ```
//!
//! ### `#[update]`
//!
//! Marks the update method. Must take `&mut self` and a message, return `Command<Msg>`.
//!
//! ```rust
//! #[update]
//! fn update(&mut self, msg: Msg) -> Command<Msg> {
//!     match msg {
//!         Msg::Tick => self.elapsed += 1,
//!         Msg::Reset => self.elapsed = 0,
//!     }
//!     Command::none()
//! }
//! ```
//!
//! ### `#[view]`
//!
//! Marks the view method. Must take `&self` and return `String`.
//!
//! ```rust
//! #[view]
//! fn view(&self) -> String {
//!     use lipgloss::Style;
//!     
//!     let style = Style::new().bold(true).foreground(Color::Cyan);
//!     style.render(&format!("Elapsed: {}s", self.elapsed))
//! }
//! ```
//!
//! ### `#[state]`
//!
//! Marks struct fields that trigger re-renders when changed.
//!
//! ```rust
//! #[derive(Model)]
//! struct App {
//!     #[state]
//!     counter: i32,           // Changes trigger re-render
//!     
//!     #[state(eq = "float_eq")]
//!     progress: f64,          // Custom equality check
//!     
//!     #[state(skip)]
//!     last_tick: Instant,     // Excluded from change detection
//!     
//!     cache: HashMap<K, V>,   // Not tracked (no #[state])
//! }
//! ```
//!
//! ## Migration from Manual Implementation
//!
//! **Before (manual):**
//! ```rust
//! struct Counter { count: i32 }
//!
//! impl Model for Counter {
//!     type Message = Msg;
//!     
//!     fn init() -> (Self, Command<Msg>) {
//!         (Counter { count: 0 }, Command::none())
//!     }
//!     
//!     fn update(&mut self, msg: Msg) -> Command<Msg> {
//!         match msg {
//!             Msg::Inc => self.count += 1,
//!         }
//!         Command::none()
//!     }
//!     
//!     fn view(&self) -> String {
//!         format!("{}", self.count)
//!     }
//! }
//! ```
//!
//! **After (derive):**
//! ```rust
//! #[derive(Model)]
//! struct Counter {
//!     #[state]
//!     count: i32,
//! }
//!
//! impl Counter {
//!     #[init]
//!     fn init() -> (Self, Command<Msg>) {
//!         (Counter { count: 0 }, Command::none())
//!     }
//!     
//!     #[update]
//!     fn update(&mut self, msg: Msg) -> Command<Msg> {
//!         match msg { Msg::Inc => self.count += 1 }
//!         Command::none()
//!     }
//!     
//!     #[view]
//!     fn view(&self) -> String {
//!         format!("{}", self.count)
//!     }
//! }
//! ```
