// crates/bubbletea-macros/examples/timer.rs
//! Timer example with async commands and #[state] tracking

use bubbletea::{run, Command};
use bubbletea_macros::Model;
use std::time::{Duration, Instant};

enum Msg {
    Tick,
    Start,
    Stop,
    Reset,
    Quit,
}

#[derive(Model)]
#[model(message = Msg)]
struct Timer {
    #[state]
    elapsed: Duration,

    #[state]
    running: bool,

    #[state(skip)]  // Internal, doesn't affect view
    last_tick: Option<Instant>,
}

impl Timer {
    #[init]
    fn init() -> (Self, Command<Msg>) {
        (
            Timer {
                elapsed: Duration::ZERO,
                running: false,
                last_tick: None,
            },
            Command::none(),
        )
    }

    #[update]
    fn update(&mut self, msg: Msg) -> Command<Msg> {
        match msg {
            Msg::Tick if self.running => {
                if let Some(last) = self.last_tick {
                    self.elapsed += last.elapsed();
                }
                self.last_tick = Some(Instant::now());
                return tick_cmd();
            }
            Msg::Start => {
                self.running = true;
                self.last_tick = Some(Instant::now());
                return tick_cmd();
            }
            Msg::Stop => {
                self.running = false;
                self.last_tick = None;
            }
            Msg::Reset => {
                self.elapsed = Duration::ZERO;
                self.last_tick = self.running.then(Instant::now);
            }
            Msg::Quit => return Command::quit(),
            _ => {}
        }
        Command::none()
    }

    #[view]
    fn view(&self) -> String {
        let status = if self.running { "Running" } else { "Stopped" };
        format!(
            "{:.1}s [{}]\n\n\
             [s] Start  [p] Pause  [r] Reset  [q] Quit",
            self.elapsed.as_secs_f64(),
            status
        )
    }
}

fn tick_cmd() -> Command<Msg> {
    Command::perform(
        async { tokio::time::sleep(Duration::from_millis(100)).await },
        |_| Msg::Tick,
    )
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    run(Timer::init)
}
