                value: T::default(),
                label: "Value".into(),
            },
            Command::none(),
        )
    }

    #[update]
    fn update(&mut self, msg: Msg<T>) -> Command<Msg<T>> {
        match msg {
            Msg::Set(v) => self.value = v,
            Msg::Clear => self.value = T::default(),
            Msg::Quit => return Command::quit(),
        }
        Command::none()
    }

    #[view]
    fn view(&self) -> String {
        format!("{}: {}", self.label, self.value)
    }
